#!/bin/bash
# Local CI Check Script
# ењЁжЋЁйЂЃе‰ЌиїђиЎЊж­¤и„љжњ¬д»ҐзЎ®дїќж‰Ђжњ‰ CI жЈЂжџҐйЂљиї‡

set -e  # Exit on error

echo "рџ”Ќ Running Local CI Checks..."
echo ""

# Color codes
GREEN='\033[0;32m'
RED='\033[0;31m'
YELLOW='\033[1;33m'
NC='\033[0m' # No Color

# Track failures
FAILURES=0

# 1. Ruff Check
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
echo "1пёЏвѓЈ  Ruff Linting Check"
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
if uv run ruff check .; then
    echo -e "${GREEN}вњ… Ruff: PASSED${NC}"
else
    echo -e "${RED}вќЊ Ruff: FAILED${NC}"
    echo -e "${YELLOW}рџ’Ў Run 'uv run ruff check . --fix' to auto-fix${NC}"
    FAILURES=$((FAILURES + 1))
fi
echo ""

# 2. MyPy Type Check
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
echo "2пёЏвѓЈ  MyPy Type Check"
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
if uv run mypy tree_sitter_analyzer/; then
    echo -e "${GREEN}вњ… MyPy: PASSED${NC}"
else
    echo -e "${RED}вќЊ MyPy: FAILED${NC}"
    echo -e "${YELLOW}рџ’Ў Fix type errors manually${NC}"
    FAILURES=$((FAILURES + 1))
fi
echo ""

# 3. Bandit Security Scan
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
echo "3пёЏвѓЈ  Bandit Security Scan"
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
if uv run --with bandit bandit -r tree_sitter_analyzer/ -f json -o bandit-results.json 2>/dev/null; then
    echo -e "${GREEN}вњ… Bandit: PASSED${NC}"
    rm -f bandit-results.json
else
    # Check if it's just a Unicode encoding error (not an actual security issue)
    if [ -f bandit-results.json ]; then
        ISSUES=$(python3 -c "import json; data=json.load(open('bandit-results.json')); print(len(data['results']))" 2>/dev/null || echo "0")
        if [ "$ISSUES" -eq "0" ]; then
            echo -e "${GREEN}вњ… Bandit: PASSED (no security issues)${NC}"
            rm -f bandit-results.json
        else
            echo -e "${RED}вќЊ Bandit: FAILED ($ISSUES security issues found)${NC}"
            FAILURES=$((FAILURES + 1))
            rm -f bandit-results.json
        fi
    else
        echo -e "${YELLOW}вљ пёЏ  Bandit: WARNING (could not verify results)${NC}"
    fi
fi
echo ""

# 4. Quick Test Run (optional - can be slow)
if [ "${SKIP_TESTS}" != "1" ]; then
    echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
    echo "4пёЏвѓЈ  Quick Test Run (unit tests only)"
    echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
    if uv run pytest tests/unit/ -q --tb=short 2>&1 | tail -20; then
        echo -e "${GREEN}вњ… Tests: PASSED${NC}"
    else
        echo -e "${RED}вќЊ Tests: FAILED${NC}"
        FAILURES=$((FAILURES + 1))
    fi
    echo ""
fi

# Summary
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
echo "рџ“Љ Summary"
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
if [ $FAILURES -eq 0 ]; then
    echo -e "${GREEN}вњ… All checks passed! Ready to push.${NC}"
    exit 0
else
    echo -e "${RED}вќЊ $FAILURES check(s) failed. Please fix before pushing.${NC}"
    exit 1
fi
